export default (n) => {
  const v = n.view;
  const when = v.when ? new Date(v.when).toLocaleString() : "sometime";
  const guests = (v.guest ?? []).map((g) => `<li>${g}</li>`).join("");
  const rsvps = (v.rsvp ?? []).map((r) => `<li>${r}</li>`).join("");
  return `<!doctype html><html><head><meta charset="utf-8"><title>${v.title ?? n.entity}</title>
<style>body{font-family:system-ui;max-width:30rem;margin:2rem auto;padding:0 1rem}
h1{font-size:1.4rem}h2{font-size:1rem;color:#666}ul{padding-left:1.2rem}</style></head><body>
<h1>${v.title ?? n.entity}</h1>
<p>${when}${v.where ? ` @ ${v.where}` : ""}</p>${v.note ? `<p><em>${v.note}</em></p>` : ""}
<h2>Guests</h2><ul>${guests || "<li>nobody yet</li>"}</ul>
<h2>RSVPs (signed)</h2><ul>${rsvps || "<li>none yet</li>"}</ul>
<form method="post"><input type="hidden" name="rsvp" value="yes"><button>I'm in</button></form>
</body></html>`;
};
